import Dashboard from '../assests/admin/admin/Dashboard';
import Profile from '../assests/admin/admin/Profile';
import Category from '../assests/admin/admin/Category';

const routes = [
    // Paths are now relative to the parent "/admin" route.
    // The `exact` prop is no longer needed in React Router v6.
    { path: 'dashboard', name: 'Dashboard', component: Dashboard },
    { path: 'category', name: 'Category', component: Category },
    { path: 'view', name: 'View', component: View },
    { path: 'profile', name: 'Profile', component: Profile },
];

export default routes;
